program BindSourceRole implements ISolver {
    type Input = str;
    type Output = bool;

    @external
    public function solve(input: Input): Output {
        create source : symbol;
        assign source = input;
        bind_role source, SOURCE;
        return true;
    }
}

program ExecuteTransfer implements ISolver {
    type Input = tuple<str, str, u64>;
    type Output = bool;

    @external
    public function solve(input: Input): Output {
        create src : symbol;
        create dst : symbol;
        bind_role src, SOURCE;
        bind_role dst, DESTINATION;
        transfer src, dst, input.2;
        return true;
    }
}

program FixMissingDestination implements ISolver {
    type Input = tuple<str, str, u64>;
    type Output = bool;

    @external
    public function solve(input: Input): Output {
        create src : symbol;
        create dst : symbol;
        bind_role src, SOURCE;
        bind_role dst, DESTINATION;   # fix: add missing binding
        transfer src, dst, input.2;
        return true;
    }
}

program IncrementQuantity implements ISolver {
    type Input = u64;
    type Output = u64;

    storage {
        stock: mutable u64 = 0;
    }

    @external
    public function solve(input: Input): Output {
        add stock, input;
        store stock, "inventory_level";
        return stock;
    }
}

program StoreEpisode implements ISolver {
    type Input = tuple<str, str>;
    type Output = bool;

    @external
    public function solve(input: Input): Output {
        create agent : symbol;
        create obj : symbol;
        assign agent = input.0;
        assign obj = input.1;
        bind_role agent, AGENT;
        bind_role obj, OBJECT;
        store agent, "episode";
        remember agent;
        return true;
    }
}

program DetectOrderPattern implements ISolver {
    type Input = array<str>;
    type Output = str;

    @external
    public function solve(input: Input): Output {
        create events : symbol;
        seq input;
        discover events, "temporal_order";
        return "ordered";
    }
}

program InsertCompareBeforeUpdate implements ISolver {
    type Input = tuple<u64, u64>;
    type Output = u64;

    @external
    public function solve(input: Input): Output {
        create value : quantity;
        create target : quantity;
        assign value = input.0;
        assign target = input.1;
        compare value, target;   # fix: verify before mutating
        add value, 1;
        return value;
    }
}

program StoreBoundFrame implements ISolver {
    type Input = tuple<str, str, str>;
    type Output = bool;

    @external
    public function solve(input: Input): Output {
        create agent : symbol;
        create action : symbol;
        create obj : symbol;
        bind_role agent, AGENT;
        bind_role action, ACTION;
        bind_role obj, OBJECT;
        store agent, "frame";
        return true;
    }
}
